async (params, browser) => {
  // Open video page
  await browser.open(`${params.video_url}`)

  // Wait for video to load
  await browser.waitForSelector('#title h1, h1.ytd-watch-metadata yt-formatted-string', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Expand description
  const expand_desc = await browser.evaluate(`const expandBtn = document.querySelector('#description-inline-expander tp-yt-paper-button#expand, ytd-text-inline-expander #expand'); if (expandBtn) expandBtn.click(); return { clicked: true }`)

  await browser.wait(1000)

  // Extract video details
  const video_details = await browser.evaluate(`const titleEl = document.querySelector('#title h1 yt-formatted-string, h1.ytd-watch-metadata yt-formatted-string'); const channelEl = document.querySelector('#channel-name ytd-channel-name a, ytd-channel-name #text a'); const subscriberEl = document.querySelector('#owner-sub-count, yt-formatted-string#owner-sub-count'); const viewsEl = document.querySelector('#info-strings yt-formatted-string span, ytd-watch-info-text .view-count, #info-strings yt-formatted-string'); const dateEl = document.querySelector('#info-strings yt-formatted-string:last-child, ytd-watch-info-text .date'); const likeBtnEl = document.querySelector('like-button-view-model button, #top-level-buttons-computed button'); const likeLabel = likeBtnEl ? (likeBtnEl.getAttribute('aria-label') || likeBtnEl.textContent.trim()) : ''; const descEl = document.querySelector('#description-inline-expander yt-attributed-string, ytd-text-inline-expander yt-attributed-string, #description yt-attributed-string'); const descText = descEl ? descEl.textContent.trim().substring(0, 2000) : ''; return { title: titleEl ? titleEl.textContent.trim() : 'Unknown', channel: channelEl ? channelEl.textContent.trim() : '', subscriber_count: subscriberEl ? subscriberEl.textContent.trim() : '', views: viewsEl ? viewsEl.textContent.trim() : '', upload_date: dateEl ? dateEl.textContent.trim() : '', likes: likeLabel, description: descText, url: window.location.href }`)

  return video_details
}
